sql:
SELECT f.filename
FROM filenames f
WHERE f.file_size = (
    SELECT MAX(file_size) 
    FROM filenames
);

external_knowledge:
- "last month" refers to the previous 30 days from the current date; 
- "most accessed" implies the songs with the highest number of accesses; 
- "lucrative" refers to the songs with the highest average selling prices.

sql:
SELECT COUNT(*) AS total_songs
FROM songs
WHERE artist = 'K.K.' AND buy_price = '3200';

SELECT COUNT(*) AS total_songs_by_artist
FROM songs
WHERE artist = 'Kurt Cobain';

SELECT name
FROM songs
WHERE song_id = 1;

SELECT name
FROM songs
ORDER BY name ASC;

